(window.webpackJsonp=window.webpackJsonp||[]).push([[70],{333:function(v,_,p){"use strict";p.r(_);var t=p(13),a=Object(t.a)({},(function(){var v=this,_=v._self._c;return _("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[_("h1",{attrs:{id:"落樱如雨"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#落樱如雨"}},[v._v("#")]),v._v(" 落樱如雨")]),v._v(" "),_("h2",{attrs:{id:"落樱如雨-2"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#落樱如雨-2"}},[v._v("#")]),v._v(" 落樱如雨")]),v._v(" "),_("p",[v._v("微观考试的压力已经置之度外了。挂了就挂了吧，也无所谓，反正本来就已经是一条无法翻身的咸鱼。努力去折磨自己，可是为了喜欢的人？当然不是，也许我曾喜欢过谁，但一定不曾有人喜欢过我。")]),v._v(" "),_("p",[v._v("经济很有意思，高鸿业的教材之所以是经典也不是没有原因。教材的背后是绚烂的经济世界，无数曲线绘制出变幻的现实市场。然而终究是无法享受经济学的多彩，一切终要归于微观挂科的结局。")]),v._v(" "),_("p",[v._v("如果运气足够好，我能得以走上成为一名工科宅的道路。那时今天所领略的经济学，也许会成为今后人生里一份宝贵的财富。但是现实往往不同于理想，多少美好的想象进皆化作泡沫般的虚妄。")]),v._v(" "),_("p",[v._v("整天沉浸水群的海洋，其实只是没有一点意思的消磨时光。现实已无法坦然面对，只好在虚幻的世界里彷徨。操纵着一切的是欲望，春天过去卸下了疯狂。爱与被爱不过是大梦的一场，尽管渴望。")]),v._v(" "),_("p",[v._v("依稀记得去年此时，还在为高考的来临而不安与烦躁。在那西家大塘的考场，把高中全部给遗忘。金陵城里的一切，化作浅浅的印象。爱过的恨过的想过的念过的，都已不再留念想。告别岁月，重怀希望。")]),v._v(" "),_("p",[v._v("十七岁的生日，是大学生涯真正的开始。仍记得那天唯一一个给我送上了祝福的女生，仍然记得那时有过的一念倾心的悸动。但，也许是那发自心底的不自信，使得我根本没有追逐的勇气。也许，人生本就是这样。")]),v._v(" "),_("p",[v._v("女生真的没有想象之中的敏感，不管你以为有多明显她们都不一定会去往那方面想。没有付诸于表白的喜欢只是一个人的喜欢，没有被明确拒绝的感情不足以称为失恋。表白失败又能降低多少效用呢？其实一点也没有。")]),v._v(" "),_("h2",{attrs:{id:"无能为力"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#无能为力"}},[v._v("#")]),v._v(" 无能为力")]),v._v(" "),_("p",[v._v("我曾经讲到过眼界与能力的关系。只有能力足够的人才配得上够高的眼界，而像我这种能力不足的人，纵使明白了一切，也无从改变。其实真正阻碍自己的永远是借口，永远是自己的内心，那你一生中最大的敌人与对手。")]),v._v(" "),_("p",[v._v("知道了这些又能怎样，无外乎增加痛苦与纠结。当你豁出去一切的时候，你就会发现没有什么事情是真正艰难的。只要能对自己下得了狠心，能战胜自己内心的反抗，再艰难的关卡也能轻松闯过。")]),v._v(" "),_("p",[v._v("依然不敢承认自己的喜欢，不敢直视自己的内心。胆怯，是那人生之中最大的缺憾。羡慕有时敢于单凭一腔热血去直面未知的自己，羡慕有时敢于不惧后果而草率决定的自己。没有一腔热血的前进，也看不见彩金湖的风景；没有不惧后果的决定，也收获不了投资的心跳与乐趣。但感情面前，永远只有畏缩不前的自己，只有瞻前顾后的自己。")]),v._v(" "),_("p",[v._v("没有必要一味放低自己，一味低估自己。尽管有无数的缺憾与不足，但仍可以努力去做最好的自己。也许所谓的近水楼台先得月，捞得的只是水中月镜中花，但为何不去一试呢？成则成矣败则败矣，倒也省去了苦恼无限。")]),v._v(" "),_("p",[v._v("微观将考，结局已定。凉凉天意，何日得以将心散尽？")]),v._v(" "),_("h2",{attrs:{id:"梦回彩金"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#梦回彩金"}},[v._v("#")]),v._v(" 梦回彩金")]),v._v(" "),_("p",[v._v("初见于冬至的前夕，那蓝天下一池碧波的浩荡。就此抛敬亭，却宛陵，一心痴迷，唯往彩金。但路途艰险，困难重重，纵心所向，不得常往。冬去春来，春尽夏始，它迷人依旧。湖畔风来，心中平静。叶子飘落，日丽风和。爱这片湖水，就像爱那一个人。也许艰难，但仍要试着去努力。伫立湖边时，总会觉得，那一切都是值得的。但路途的愈发艰苦终究断绝了念头，正如情路的坎坷迷茫斩断了所有的想象。别了，彩金。别了，湖心那片终将落下的树叶。")]),v._v(" "),_("p",[v._v("爱不得归宿，古都金陵多少往事，月下宣州几分伤情。心不得平息，口是心非忘却自我，十里桃花花开花落。爱的透彻，只能让自己难受。爱的卑微，只能让痛苦滋生。如果快乐太难，那就祝你平安。离去为放下向往，远遁怕遇见情伤。")]),v._v(" "),_("p",[v._v("犹记得，那最后的一天，把堆积如山的书收拾收拾，带走教室里的一切，也包括那些幻想与不切实际。到了旅途预期的终点，一切早已漠然，最后望一眼这个待了三年的地方，看着老师和我们一起离开，再也回不来了。那年的记忆，也许只剩下了樱花树下青涩的美好。终究，时光滚动着前进，又是一年过去了。看牛头冲的一切，看那崇山峻岭环抱的一方天地，也许那时的一切都不曾有过，都只是一串流于符号的记忆吧。犹记那年樱花盛开，犹记那年白雪皑皑。熟悉的早已成为过去，曾经的早已成为陌路。出走未久，便已找不到回头的路；离开几时，便已寻不着来时的方向。浪过了，错过了，一切也都归于平静了。人海茫茫，很多人，一旦消失，便不再。也许，应该珍惜每一个令我怦然心动的人，即使再难，即使再多不可能。但，现实终究艰难，也许也许终究只是也许。")]),v._v(" "),_("p",[v._v("一年的时光就这样匆匆过去，蓦然回首，一切，都已经不一样了。似乎已经过去了很久很久，似乎那时的一切已经远在天边。")]),v._v(" "),_("p",[v._v("其实，高考并没有什么特殊的感觉，不过是一段旅途的终点。也该放松了，也该丢下那些行囊了。走出考场，圆满了高中的三年，拜别了曾经的岁月。熟悉的面孔消散在云烟，熟悉的地方再也回不来。旅途的前方坐落着未知与迷茫，不管不顾，我自前往。")]),v._v(" "),_("p",[v._v("高中三年，是幸，也是不幸。也许有那么多值得留恋的记忆，有那么多值得怀念的往昔。但是，身份的错位与迷茫，情感的放浪与忧伤，缠绕着自己，无法自拔。挂念的人，终究离得太远。不在一个世界里，真的难以接近。")]),v._v(" "),_("p",[v._v("高考之后，那是一个火热的夏天。四十度的灼热，烧干了每一重对过去的回忆。曾经熟悉的人一下就断了联系，曾经熟悉的面孔一下就消失天际。三年的交情本就淡薄，何必如此看重？人的本质，其实只是孤独。")]),v._v(" "),_("p",[v._v("于是就走进了牛头冲这片土地，认识了天南海北的人们，也见识了不一样的自己。人可以不那么孤独，可以投身人群来放纵自我。欣赏不一样的风景，看着不一样的人。该忘的，都忘掉吧。让记忆化为泡影，往事留作尘埃。")]),v._v(" "),_("p",[v._v("喜欢自己一个人，去看那没看过的风景。生活充满着美，不必老是去想那些无奈。喜欢心里一个人，看她的喜怒哀乐，给生活点缀了光芒。单纯的喜欢，无关风月，纵使伤感，纵使遗憾。也许我应该去勇敢追逐，但终究没有那份自信。那，便算了吧。")]),v._v(" "),_("p",[v._v("也许曾有过一份初心，也许曾有过几分傲气。但现实终究击败了初心，生活终究消灭了傲气。转专业是内心真实的想法，还是怯懦者无谓的逃避？其实更多的是后者。不必多想，不必多念。凭心而动，也是一种人生。")]),v._v(" "),_("p",[v._v("曾经，早已成过眼云烟。西家大塘那棵树下，等时光流淌，等走进考场，等光阴谢幕，叹纸短情长。散了，散了。再见了过去的一切，离开了曾经的所有，重头开始，不似从前。")]),v._v(" "),_("p",[v._v("没有在这里遇上这个人，也会在那里遇上那个人。缘是说不清道不明的东西，不因位置的改变而改变。纵使没来牛头冲，也会去另一个地方，看到另一个人，并迷恋上她。有些事，是命里所注定的，没法逃避，更没法去改变。我相信命运。")]),v._v(" "),_("p",[v._v("回顾自己的内心，我是真的喜欢她吗？也许并不一定。世上有许许多多的美值得欣赏，而她充其量只是其中之一。但为什么会痴迷，为什么会牵念，却已不是我所能知道的了。")]),v._v(" "),_("p",[v._v("之所以能进入牛头冲，靠的不是实力，而是那积攒的运气。虽然能力相去仍远，但这运气至少让我有了一望的可能。一念倾心，心在哪里？早就没有什么好想的了。不后悔来到这个学校，不后悔选择了经济学。但是前方的路该怎么走，是否应该一个人孤单前行？答案仍然在未知的前方。")]),v._v(" "),_("p",[v._v("丧，也许是因为天气，但是更多的是因为内心。也许是被某人的话戳中了痛点，为自己的怯懦而痛心。不试试怎么知道呢？即使失败了也是好的啊。但就是不得解脱，也不敢向前一步。不后悔自己所选择的一切，只后悔自己遇上了她。")]),v._v(" "),_("p",[v._v("高考结束的那一刻，青春已落下帷幕，青春才刚刚开始。高考过去一年，过往的一切记忆都已封存，只会在那午夜梦回之时猛然忆起。过去的终究是要忘掉的，毕竟那个世界里，并不应该有我的身影。")]),v._v(" "),_("p",[v._v("一年后，仍然有着一场考试等待着我。它虽无足轻重，它又意义非凡。C语言，让我认识了许许多多的形形色色的人，让大学生活变得丰富多彩了起来。它也让我重拾起那时放下的初心，决定在转专业的路途上前进，作为，那逃避情感的一条退路。")]),v._v(" "),_("p",[v._v("枕头里藏满了发了霉的梦，梦里住满了无法拥有的人。真正适合我的人，也许还没有出现。喜欢的，不一定是最好的；不喜欢的，一定不是最好的。不愿直面的情感，就当它是爱吧。 淮阳远去的方向飘来了片片树叶，落入心中的湖水，泛起道道涟漪。")]),v._v(" "),_("p",[v._v("已然忘却了那时发生的一切，只记得无人相伴，独自一人，从未想象过如今。我们不能预测将来，我们只能抓住现在。现在喜欢的人，这一刻，是否应该让她属于我呢？")]),v._v(" "),_("h2",{attrs:{id:"渐醉渐远"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#渐醉渐远"}},[v._v("#")]),v._v(" 渐醉渐远")]),v._v(" "),_("p",[v._v("日暮时分，晚霞与云朵的结合，爆发出一天里阳光最后的绚烂。远处的宣州城已华灯初上。摩天轮的一抹光华，在霞光的映衬下更显多姿。转眼间，来到这片土地，快有一年了。眼见着翡翠华庭从荒芜之地变成繁花似锦，眼见着图书馆点亮湖滨的风景。眼见着万达广场渐渐变得清晰，眼见着宣城新站的崭新与靓丽。一山一水，一宣州。皖南的这座小城里，每一天都在发生新的变化，每一天都在为发展而努力。虽然比不上大城市的瞬息万变，但也有着别样的风景。最好的朋友都在身边，喜欢的人就在这里。在这大一最后的岁月里，享受着恬淡的小幸福。有的时候，错过，也许才是最好的。")]),v._v(" "),_("p",[v._v("也许，我仍幻想着挽留时光，不想把往日彻底封藏。也许，我还保留着些许回忆，不想让过去完全消亡。但眼见着他们变成了不常用联系人，群聊走进了不常用群聊窗，算了，放下吧。不留念想，不剩希望。留下孤独的自己，走进寂寞的坟场。生命中的过客们许许多多，值得留恋的没有几个。也许以后会有一天，我们偶然相遇，不过互道一声，你好。无论是否是爱过，是否是错过，过去的，终究是过去了。")]),v._v(" "),_("p",[v._v("宣州的夏天，又一次降临了。但好像一切都失去了本来的味道，包括初心，包括向往，包括目标，包括前方。好像关乎风月的时光早已不再流淌，没有思慕，没有情愫，没有念想，没有希望。我记忆里的，还是那清纯的模样，一切都简单纯粹，淡淡的美貌，显得刚刚好。没有太多喧嚣，没有太过浮躁。渐渐地，叶子黄了，雪花飘了，春风过了，烈日又一次回到了宣州的天空。她漂亮了，但已经不再是那时干净的样子。爱，其实并不真实，只是一种飘渺在云端的感觉，也许走入了真实的世界里，就不复存在了吧。无关风月的才是故事，关乎风月的只是幻境。")]),v._v(" "),_("p",[v._v("真正喝到醉了，还是不敢表白，但闭上眼睛，眼前全是你的模样。逃避发自内心，纵午夜梦回，泪落枕边，心碎成一片片。不敢正视，也不敢放手。一个人痛苦，也就够了吧。天亮了，第一个在村里度过的假期真正开始了。忘掉那些人和那些事吧，一切都会好起来的。")]),v._v(" "),_("h2",{attrs:{id:"心无所依"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#心无所依"}},[v._v("#")]),v._v(" 心无所依")]),v._v(" "),_("p",[v._v("一切的开始，是黑暗的。直到那一天，我看见，那来自天边的一缕微茫。光越来越亮，让我痴迷，让我向往。我追逐光，但光总是背离我的方向。试着去追赶，光却越来越远，越来越暗淡。直到乌云遮蔽了光芒，起风了，放下了。停下脚步，回味那光的美好，却见那天边，是两道彩虹，正闪耀着光。")]),v._v(" "),_("p",[v._v("暮色四合，天空陷入了苍茫深蓝。光的影，终究消逝了。只有那彩色的记忆，依然存在着，不会消逝。也许，关于她的记忆，就像这彩虹一样，会是永远美好的吧。")]),v._v(" "),_("p",[v._v("在我的性格里，本有着诸多的弱点。矛盾与冲突，才是我性格的主旋律。也许我在很多时候都愿意去谨小慎微，但总有那么一段时间不愿去计较是非因果。许多人不喜欢我，更多人挺讨厌我，这也没关系，有人不那么讨厌我就好。")]),v._v(" "),_("p",[v._v("曾经，我也是个不那么活跃和积极的人。爬一爬山，游一游湖，看一看山水之间，那宣州城别样的风景。整理好那似是而非的往事，默默地在心底里喜欢着一个人。淡泊宁静，无人打扰，独自享受，那份天地之间的清寂。在各种各样的比赛里忙碌，有着淡淡的伤感，也有着小小的幸福。")]),v._v(" "),_("p",[v._v("不知道从什么时候开始，我变了。沉浸在虚拟的网络世界里，去跟一个个见过但更多的是没见过的人天南海北地聊着，似乎一刻不看群就不舒服似的。但是实际上，要关注的，本没有那么多。")]),v._v(" "),_("p",[v._v("也许，只是因为对爱情绝望了吧。")]),v._v(" "),_("h2",{attrs:{id:"再逢七七"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#再逢七七"}},[v._v("#")]),v._v(" 再逢七七")]),v._v(" "),_("p",[v._v("飞逝的时光里埋葬着过往和曾经，皖南的小城中磨灭了梦想与初心。也许还有几分书生意气，也许还怀多少幻想回忆。一晃，已经快过去三百天了。三百天，不算长，不算短。长到足够忘却自我，短到难以忘却时光。过度修仙，飘忽不定；放纵自我，一片狼藉。尽力不去想，不去念，但终究有所触动，有所牵连。遗憾不算遗憾，叹惋不必叹惋。既已做出了选择，那就不再悔过。前方的路仍然漫长，不如寻找前方的姑娘。")]),v._v(" "),_("p",[v._v("人事将尽，剩下的全听天意。随波逐流，磨灭掉三分傲气。曾经想要努力，也曾喜欢着你。渐落得初心无觅，渐生得几分去意。也许并非不适合经济，也许未必擅长于信息。趁早把一切封存回忆，不管未来是否会惋惜。叹落花有情流水无意，不如闭门来反思自己。若是走远，那就把一切归于沉寂；若仍驻留，就不把念想埋藏心底。一晃已经入夏，一晃即将入秋，一晃又要到那叶子落的季节里。踏过十八岁，面对的，又会是怎样的自己？")]),v._v(" "),_("p",[v._v("七月七日晴/忽然下起了大雪/不敢睁开眼/希望是我的幻觉/我站在地球边/眼睁睁看着雪/覆盖你来的/那条街。七月七日，晴间小雨。睁开眼，看时间，却忽然想起，从前。")]),v._v(" "),_("p",[v._v("十一年前，七月七日，告别了两江环绕的重庆，来到了几分生疏的金陵城。单纯无知的我，并不知道在这座城市会发生什么。还抱着几分天真的幻想，以为世间，尽是美好。")]),v._v(" "),_("p",[v._v("时光渐渐过去，现实让我放弃了幻想，黑暗让我抛下了天真。那是一段多么不愿记起的遥远岁月啊，尽力在黑暗中喘息，没有光明，没有未来。挣扎在岁月里，却看不到明天。")]),v._v(" "),_("p",[v._v("也许从西藏归来时，那高中的开始，让世界开始有了几分光明。但三年前，那个七月七日的离别，却让那份光明蒙上了几分阴影。喜欢的人远了，压力和竞争近了。各色利益，各色冲突，如一池碧水，在表面的清澈之下，却是一片污浊与黑暗。")]),v._v(" "),_("p",[v._v("又到了七月七日。难得快乐的一年时光，难得美好的一载年华。近在眼前的期末，早已不放在心间。七月七日晴/黑夜忽然变白天/我失去知觉/看着相爱的极限/我望着地平线/天空无际无边/听不见你道别")]),v._v(" "),_("p",[v._v("时光的尽头，剩不下多少从容。一年到了终点，竟已无话可说。也许就只能这样了吧，做熟悉的陌生人，在该配合演出的时候演视而不见，管他是不是只能即兴表演。云不淡，风不轻，阳光似火，一影独行。什么时候开始没有了底线，什么时候开始随心所欲表演。没有观众没有剧组，顺着谎言被动就不显得可怜。反正是蹩脚的演员，反正是随心所欲的表演。静静地回味一遍过去，也许一切，本不应该是这样。")]),v._v(" "),_("h2",{attrs:{id:"故事尽头"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#故事尽头"}},[v._v("#")]),v._v(" 故事尽头")]),v._v(" "),_("p",[v._v("药医不死病，佛度有缘人。 吕受益，彭浩(黄毛)，刘牧师，还有刘思慧的女儿…他们是幸运的，他们有缘遇上了能给他们带来生机的程勇。但他们又是不幸的，程勇放弃了药品走私，让吕受益因没有药品而走上了绝路；警察的追捕，让彭浩丧生在车轮之下…在生命和法律之间，他们毫不犹豫地选择了生命。绝望，是最大的悲哀。")]),v._v(" "),_("p",[v._v("科学技术的发展，让生和死这最后一丝的公平也化为云烟。钱就是命，格列卫就是慢粒白血病人的命。许多人钱没了，命也没了。于是乎，最终而言，人只有一种病，那就是穷病。我们不能指责谁对谁错，因为没有谁是错的。程勇想救人，病人想活命，药商要维权，警方要破案。生与死，贫与富。这是一部让人笑不出来的喜剧，也是一部让人哭不出来的悲剧。")]),v._v(" "),_("p",[v._v("没有什么愿景，也没有什么期待。烈日的灼烧之下，一切都在黯然间褪色。第一次，可能也是最后一次了。曾经想说但没说的，就不说了吧；曾经想做但没做的，就不做了吧。把时光退回一切开始的那一天，退回那仿佛已经很远很远的从前。无所谓喜欢，无所谓情感。还没有开始的故事，就已经结束了。想想矛盾的普特关系，想想纠结于一个人有什么意义。且恢复平常心，不去作，不去自找罪受。")]),v._v(" "),_("p",[v._v("夏天到秋天，秋天到冬天，冬天到春天，春天又到夏天。十二个月的时光，任回忆被时光抹去。曾经三载的青春，任距离把岁月消灭。走过北京东路没有了感觉，鸡鸣寺路的樱花只剩下了记忆。西家大塘的战斗已经过去很远，碑亭巷口的日子也难得再留恋。车水马龙声一去不复返，只留得牛头冲的阵阵蝉鸣。梧桐絮落如雨的时节里，再也体会不到，蒋公与美龄的爱情。烟花易冷，春水易逝。曾以为那片叶子的爱情纯真美好，但却在意外间埋葬。一念倾心，不留痕迹。")]),v._v(" "),_("p",[v._v("看过城市的繁华喧嚣，也看过乡村的宁静从容。但我的心最终沉浸在，那一抹湖水之中。滚滚的乌云，遍布那金陵的空；片片的山林，吹过那郊野的风。不得安生的心灵，游荡在城东；分明不曾去拥有，却说太匆匆。道路崎岖难行，历经坎坷无穷；旅途一向艰苦，人生从未轻松。叶子该落了，心也该散了，毕竟，方向错了，注定只是徒劳无功。")]),v._v(" "),_("p",[v._v("最后的奔波，随即踏上前途。高温与酷暑，不必算作折磨。正如单相思腐蚀着心灵，烈日的骑行灼烧了肉体。大江东去，滚滚江水带不去点点思慕，也留不下一分儿女情长。坦然面对有过的情感，放下所有虚妄的幻念。浪漫似香榭丽舍的偶遇般的开端，终究会化作浮华过后的泡影。现实，才是对自己最好的成全。也许，我所要的，只是她，只有她，只要她。不知姓名，不知死活。")]),v._v(" "),_("p",[v._v("所谓的不可能的人，也许就是自己给自己设下的枷锁。你认定了，就真的不可能了。得不到的永远在骚动，被偏爱的都有恃无恐。一念倾心，既已倾注，则唯有毁灭一途。弱势的一方总是受挫，卑微的追求让人折磨。放下，则是洒脱。江湖再见，已然无缘。")]),v._v(" "),_("p",[v._v("也许我也应该学会沉默了。心累到啥都不想说。一切都是我的错吧。妄想过度神思恍惚吧。一个人好好的为啥要想那么多？还是安静吧，把时间留给内心吧，想想自己要啥吧。再好看的妹子不是你的，再美丽的风景不是你的，再成功的人生也不是你的。不如承认你就是个loser，在生活中失意，在现实中伤心。这样，说不定还能好受些。")]),v._v(" "),_("h2",{attrs:{id:"花开半夏"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#花开半夏"}},[v._v("#")]),v._v(" 花开半夏")]),v._v(" "),_("p",[v._v("本以为，最为迷茫的时节已经过去。放下曾经怀有过的幻想，就得以翻开新的篇章。但现实却是，在无尽的时光里奔忙。没有向往，更没有了前方。盘旋在山道上，心无所伤。敬亭宛溪，夏渡向阳。找不回昔日骑行的欢畅，抛弃了曾经放纵的疆场。感谢在这个月里关心我的所有人，让我在最软弱的时刻里选择坚强。纵浑身是伤，仍不想绝望。")]),v._v(" "),_("p",[v._v("天色已然迟暮，太阳收敛了光芒。深邃幽蓝的空中，繁星特别明亮。还有那么一片温暖的，是白月光。流连在群星璀璨里，却再也找不到心之所向。也不知，那迷惑了视野的，是那月的清朗，还是那星的微茫。抑或着，还在回想，那日未落的时光。")]),v._v(" "),_("p",[v._v("只好选择，在天台孤独地守望。念念不忘的，也许终究会有回响吧。")]),v._v(" "),_("p",[v._v("生活，就此走向新的起点。故事，没有过去也没有将来。无疾而终的念，如奔流的滔滔江水，一去，便再不复回。再莫谈及那些过往，再莫回想曾经故事。所有人都是好人，除我以外。我不是坏人，但更不是好人。")]),v._v(" "),_("p",[v._v("星空的璀璨，在于它的变幻。人生如流星，在宇宙间走走停停，被每一颗星影响，也影响每一颗星。一许流星划破天空，带着耀眼的光芒，让人沉醉，令人倾心。但当它离去时，除去无可奈何，也并无它想。直到一天，你发现一颗与你相互吸引的星，互相围绕，牢牢相依。这，才是所追寻的幸福。")]),v._v(" "),_("p",[v._v("世界不是一个人的世界。你的好心对别人未必是好意，一味的想做好人只会被欺。要遵从自己的内心，也要对得起自己的良心。做好事前先多考虑一下自己，做坏事前先多考虑一下别人。好报和恶报这种东西，都挺虚无缥缈的，谁也不知道它会应验在哪里。不用去想好心有没有好报，恶意有没有恶报。对得起自己的良心就好。每个人的追求不尽相同，有的人追名，有的人逐利；有的人求道，有的人修仙。还有的人求子孙安乐，还有的人求一世幸福。想法不同，追求不同，行为自然也不尽相同。笼统的定义好人和坏人，并不靠谱。在我看来，好人，是他所做好事的影响比坏事产生的影响大得多的人，坏人亦然。我们既不能算是好人，也算不上坏人，我们都只是凡人。")]),v._v(" "),_("p",[v._v("再回宣州，再逢，宣州雨。初到宣州时的点点忧伤已经散尽，而初到宣州时的点点迷茫，却愈发深沉。仍能想起宣州赋的慷慨激昂，但也会忆起消愁的自由与远方。其实，都是假象。离开宣州的日子里，思念宣州，思念宣州雨落，一片凉凉夜色。岁月静好的日子里，把心彻底埋葬。你若有光，便是远方。念念不忘，必有回响。但，这世上，没有什么值得念念不忘，也没有什么值得回响。光，本就在远方。看到了，也就足够了。")]),v._v(" "),_("p",[v._v("当再一次越过宛陵湖来到宣州的城中，时间仿佛回到曾经的初秋。军训刚刚结束时青涩的自己，还不知道什么是春夏什么是秋冬。憧憬与冲动早已过去，平淡的日子需要刺激。做回曾经自己的自己，不要为了他人而掩饰内心。坦然放弃过去，才能迎接未来。")]),v._v(" "),_("p",[v._v("当一切回归了最开始的模样，我不认识你，你不认识我。这是最好的开始，也是最好的结局。进村第三百六十五天，做完能做的事，然后且听天命。见完要见的人，然后径自离去。不得真假，不做挣扎。放下那水群的岁月，放下那哗众取宠的日子，放下那不该再念的人。春风十里，那曾经想念过的人，也许不知不觉，就见过了最后一面。")]),v._v(" "),_("p",[v._v("犹记得上一个9月12日，那是开学典礼的日子。领导们在台上说，我们在台下听。新的生活正式地由此开始，旧的故事渐渐地画上句号。结束的结束，开始的开始。祝福过我的人，我为你祝福。")]),v._v(" "),_("p",[v._v("又一个9月12日，平淡，而又幸运。感谢室友和刘总，感谢两位小姐姐。感谢经济一班，伴随我度过了迷茫；感谢电信二班，往后的日子还需同行。成年了，一切回到最初的起点。过去，告别，道一声再见；未来，您好，请多多关照。")]),v._v(" "),_("p",[v._v("也许一切，就这么结束了吧。")])])}),[],!1,null,null,null);_.default=a.exports}}]);